import{_ as e,o as d,c as o,ag as n}from"./chunks/framework.HG0H2VLS.js";const m=JSON.parse('{"title":"Banner — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/patterns/Banner/Banner.figma-notes.md","filePath":"public/demos/src/patterns/Banner/Banner.figma-notes.md"}'),a={name:"public/demos/src/patterns/Banner/Banner.figma-notes.md"};function i(r,t,c,s,l,g){return d(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="banner-—-figma-notes" tabindex="-1">Banner — Figma Notes <a class="header-anchor" href="#banner-—-figma-notes" aria-label="Permalink to &quot;Banner — Figma Notes&quot;">​</a></h1><h2 id="figma-node" tabindex="-1">Figma Node <a class="header-anchor" href="#figma-node" aria-label="Permalink to &quot;Figma Node&quot;">​</a></h2><ul><li><strong>File:</strong> <code>Lus07xi8pPXLN87sQIyrEt</code> (Affino AI Design System)</li><li><strong>Component set / container:</strong> <code>2550:2225</code> (&quot;Container&quot; frame)</li><li><strong>Tier:</strong> <code>Pattern</code> (built into <code>src/patterns/Banner/</code>)</li><li>URL: <a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=2550-2225" target="_blank" rel="noreferrer">https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=2550-2225</a></li></ul><h2 id="variant-matrix-12-variants" tabindex="-1">Variant matrix (12 variants) <a class="header-anchor" href="#variant-matrix-12-variants" aria-label="Permalink to &quot;Variant matrix (12 variants)&quot;">​</a></h2><p>Properties: <strong>Type</strong> × <strong>Device</strong> × <strong>Position</strong> = 3 × 2 × 2 = 12.</p><table tabindex="0"><thead><tr><th>Node ID</th><th>Type</th><th>Device</th><th>Position</th><th>Built</th></tr></thead><tbody><tr><td>2550:2224</td><td>Announcement</td><td>Desktop</td><td>Floating</td><td>✅ via <code>.banner--announcement.banner--floating</code></td></tr><tr><td>2550:2220</td><td>Announcement</td><td>Desktop</td><td>Fixed</td><td>✅ via <code>.banner--announcement.banner--fixed</code></td></tr><tr><td>2550:2218</td><td>Announcement</td><td>Mobile</td><td>Floating</td><td>✅ via <code>@media (max-width: 767px)</code></td></tr><tr><td>2550:2222</td><td>Announcement</td><td>Mobile</td><td>Fixed</td><td>✅ via <code>@media (max-width: 767px)</code></td></tr><tr><td>2550:2219</td><td>Marketing</td><td>Desktop</td><td>Floating</td><td>✅ via <code>.banner--marketing.banner--floating</code></td></tr><tr><td>2550:2216</td><td>Marketing</td><td>Desktop</td><td>Fixed</td><td>✅ via <code>.banner--marketing.banner--fixed</code></td></tr><tr><td>2550:2223</td><td>Marketing</td><td>Mobile</td><td>Floating</td><td>✅ via <code>@media (max-width: 767px)</code></td></tr><tr><td>2550:2215</td><td>Marketing</td><td>Mobile</td><td>Fixed</td><td>✅ via <code>@media (max-width: 767px)</code></td></tr><tr><td>2550:2217</td><td>Information</td><td>Desktop</td><td>Floating</td><td>✅ via <code>.banner--information.banner--floating</code></td></tr><tr><td>2550:2214</td><td>Information</td><td>Desktop</td><td>Fixed</td><td>✅ via <code>.banner--information.banner--fixed</code></td></tr><tr><td>2550:2221</td><td>Information</td><td>Mobile</td><td>Floating</td><td>✅ via <code>@media (max-width: 767px)</code></td></tr><tr><td>2550:2213</td><td>Information</td><td>Mobile</td><td>Fixed</td><td>✅ via <code>@media (max-width: 767px)</code></td></tr></tbody></table><p>Device variants are handled responsively in CSS — there are no <code>.banner--mobile</code> modifier classes. Resize the viewport below 768px to see mobile layout.</p><h2 id="css-class-mapping" tabindex="-1">CSS Class Mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS Class Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma element</th><th>CSS class</th><th>Notes</th></tr></thead><tbody><tr><td>Container (root)</td><td><code>.banner</code></td><td>Base flex row, white bg, secondary border</td></tr><tr><td>Position=Floating</td><td><code>.banner--floating</code></td><td>Adds <code>--ai-radius-md</code> (Announcement) or <code>--ai-radius-lg</code> (Marketing/Information) + <code>--ai-shadow-md</code></td></tr><tr><td>Position=Fixed</td><td><code>.banner--fixed</code></td><td>Square corners, bottom-border only, no shadow</td></tr><tr><td>Type=Announcement</td><td><code>.banner--announcement</code></td><td>Single-row icon-bubble + text + close</td></tr><tr><td>Type=Marketing</td><td><code>.banner--marketing</code></td><td>Logo + body + dual-CTA + close (close is absolute top-right)</td></tr><tr><td>Type=Information</td><td><code>.banner--information</code></td><td>Body + Sign Up + close (inline desktop / absolute top-right mobile)</td></tr><tr><td>Icon bubble (Announcement)</td><td><code>.banner__icon</code></td><td>40px, brand-soft-extra bg, full radius</td></tr><tr><td>Logo square (Marketing)</td><td><code>.banner__logo</code></td><td>56px, brand bg, radius-md, accepts a Lucide icon at 32px</td></tr><tr><td>Heading</td><td><code>.banner__title</code></td><td><code>--ai-font-fixed-md</code> (18px) bold</td></tr><tr><td>Paragraph / announcement text</td><td><code>.banner__text</code></td><td><code>--ai-font-fixed-xs</code> (14px) regular</td></tr><tr><td>Inline link (Announcement)</td><td><code>.banner__link</code></td><td>Semibold, brand-coloured, underlined</td></tr><tr><td>Action group</td><td><code>.banner__actions</code></td><td>Flex row of buttons</td></tr><tr><td>Dismiss button</td><td><code>.banner__close</code></td><td>Default inline; positioned absolute for Marketing (always) and Information (mobile only)</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma variable</th><th>CSS variable</th><th>Used for</th></tr></thead><tbody><tr><td><code>surface/elevated-1</code></td><td><code>--ai-surface-elevated-1</code></td><td>Banner background (steps up properly in dark mode vs <code>surface/primary</code>)</td></tr><tr><td><code>border/secondary</code></td><td><code>--ai-border-secondary</code></td><td>Border (full when Floating, bottom-only when Fixed)</td></tr><tr><td><code>surface/brand-soft-extra</code></td><td><code>--ai-surface-brand-soft-extra</code></td><td>Announcement icon bubble background</td></tr><tr><td><code>surface/brand</code></td><td><code>--ai-surface-brand</code></td><td>Marketing logo background AND announcement icon fill (Figma binds the icon stroke to surface-brand, not icon-brand)</td></tr><tr><td><code>text/primary</code></td><td><code>--ai-text-primary</code></td><td>Heading + announcement body text</td></tr><tr><td><code>text/contrast</code></td><td><code>--ai-text-contrast</code></td><td>Marketing/Information paragraph</td></tr><tr><td><code>text/brand</code></td><td><code>--ai-text-brand</code></td><td>Announcement inline link</td></tr><tr><td><code>btn/primary-text</code></td><td><code>--ai-btn-primary-text</code></td><td>Marketing logo content (icon/letter) — supersedes the older <code>text/invert</code> binding</td></tr><tr><td><code>icon/contrast</code></td><td><code>--ai-icon-contrast</code></td><td>Close button icon</td></tr><tr><td><code>radius/md</code></td><td><code>--ai-radius-md</code></td><td>Announcement floating, button corners, close button</td></tr><tr><td><code>radius/lg</code></td><td><code>--ai-radius-lg</code></td><td>Marketing/Information floating</td></tr><tr><td><code>radius/full</code></td><td><code>--ai-radius-full</code></td><td>Announcement icon bubble</td></tr><tr><td><code>light/shadow-md</code></td><td><code>--ai-shadow-md</code></td><td>Floating drop shadow</td></tr><tr><td><code>spacing/2</code> (6px)</td><td><code>--ai-spacing-2</code></td><td>Title→paragraph gap</td></tr><tr><td><code>spacing/3</code> (8px)</td><td><code>--ai-spacing-3</code></td><td>Action gap, close button corner offset</td></tr><tr><td><code>spacing/4</code> (12px)</td><td><code>--ai-spacing-4</code></td><td>Default banner gap, announcement padding-y</td></tr><tr><td><code>spacing/5</code> (16px)</td><td><code>--ai-spacing-5</code></td><td>Mobile padding</td></tr><tr><td><code>spacing/6</code> (24px)</td><td><code>--ai-spacing-6</code></td><td>Information desktop padding, announcement padding-x</td></tr><tr><td><code>spacing/7</code> (32px)</td><td><code>--ai-spacing-7</code></td><td>Marketing desktop padding + gap</td></tr><tr><td><code>spacing/8</code> (40px)</td><td><code>--ai-spacing-8</code></td><td>Announcement icon bubble size</td></tr><tr><td><code>spacing/10</code> (56px)</td><td><code>--ai-spacing-10</code></td><td>Marketing logo size</td></tr><tr><td><code>font/title</code></td><td><code>--ai-font-title</code></td><td>Heading + Marketing logo letter font</td></tr><tr><td><code>font/fixed-md</code> (18px)</td><td><code>--ai-font-fixed-md</code></td><td>Heading</td></tr><tr><td><code>font/fixed-xs</code> (14px)</td><td><code>--ai-font-fixed-xs</code></td><td>Body text</td></tr><tr><td><code>font/fixed-xl</code> (22px)</td><td><code>--ai-font-fixed-xl</code></td><td>Marketing logo letter</td></tr><tr><td><code>leading/sm</code> (20px)</td><td><code>--ai-leading-sm</code></td><td>Heading; mobile announcement text</td></tr><tr><td><code>leading/md</code> (24px)</td><td><code>--ai-leading-md</code></td><td>Desktop announcement &amp; paragraph text</td></tr></tbody></table><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><p>None — every design value maps to an existing <code>--ai-*</code> token.</p><p><strong>Note on shadow:</strong> the <code>light/shadow-md</code> Figma effect resolves to a 10px blur in the Variables panel but Figma&#39;s design-context CSS export emits <code>0 2px 5px rgba(0,0,0,0.1)</code> (5px blur). The component uses <code>var(--ai-shadow-md)</code> since that is the bound token — a small visual delta versus the in-Figma rendering may exist. Flag to the designer if the effect token needs reconciling.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><strong>Tier=Pattern → <code>src/patterns/</code>.</strong> The Figma component property is <code>Tier=Pattern</code>, so the file lives in <code>src/patterns/Banner/</code> per project convention even though the user&#39;s request mentioned <code>src/components/</code>.</li><li><strong>Close button positioning is per-type:</strong><ul><li>Announcement: always inline at end of row.</li><li>Marketing: always absolute top-right.</li><li>Information: inline at end of row on desktop; absolute top-right on mobile.</li></ul></li><li><strong>Marketing mobile drops &quot;Learn more&quot;.</strong> The mobile variant only shows Sign Up (full-width). The CSS hides <code>.btn--tertiary</code> inside <code>.banner--marketing .banner__actions</code> at mobile widths so the same HTML works for both desktop and mobile.</li><li><strong>Marketing logo content is flexible.</strong> The <code>.banner__logo</code> slot accepts either a Lucide icon (sized at <code>--ai-icon-size-xl</code>/32px), a single letter, or a small image. The demo uses a Lucide <code>award</code> icon as a placeholder for the brand mark in Figma.</li><li><strong>Fixed height.</strong> Figma marks Announcement at <code>h-[66px]</code>. The component lets natural padding + content height drive the height instead — this avoids hardcoding a non-token pixel value and the result is visually equivalent (~64–66px depending on borders).</li><li><strong>Subpixel padding values in Figma</strong> (e.g. <code>pb-[13px]</code>/<code>pt-[12px]</code>) are sub-pixel rounding artefacts of the bound <code>--ai-spacing-4</code> token (12px). The CSS uses the canonical token value.</li><li><strong>Announcement Mobile uses <code>--ai-leading-sm</code> (20px)</strong> instead of <code>--ai-leading-md</code> (24px) for the body text — a deliberate Figma-specified difference, applied via the <code>@media (max-width: 767px)</code> block.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li><code>Button</code> (<code>src/components/Button/</code>) — used inside <code>.banner__actions</code> for the Sign Up / Learn more CTAs.</li><li>Lucide icons via CDN — <code>megaphone</code> (announcement), <code>award</code> (marketing logo placeholder), <code>x</code> (close).</li></ul>',18)])])}const b=e(a,[["render",i]]);export{m as __pageData,b as default};
